<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { orderApi, type Order } from '@/api/services'
const active = ref('ALL'); const orders = ref<Order[]>([]); const loading = ref(true); const operating = ref(''); const labels: Record<string, string> = { ALL: '全部', PENDING_PAYMENT: '待付款', PAID: '待发货', SHIPPED: '待收货', COMPLETED: '已完成', CANCELED: '已取消' }; const displayed = computed(() => active.value === 'ALL' ? orders.value : orders.value.filter((item) => item.status === active.value)); const price = (value: number) => Number(value).toFixed(2)
const load = async () => { loading.value = true; try { orders.value = (await orderApi.list({ page: 1, size: 100 })).items } finally { loading.value = false } }; const confirm = async (orderNo: string) => { try { await ElMessageBox.confirm('确认已经收到商品吗？', '确认收货', { type: 'info' }) } catch { return } operating.value = orderNo; try { await orderApi.confirm(orderNo); ElMessage.success('已确认收货'); await load() } finally { operating.value = '' } }; const cancel = async (orderNo: string) => { try { await ElMessageBox.confirm('取消后将释放库存，是否继续？', '取消订单', { type: 'warning', confirmButtonText: '确认取消' }) } catch { return } operating.value = orderNo; try { await orderApi.cancel(orderNo); ElMessage.success('订单已取消'); await load() } finally { operating.value = '' } }; onMounted(load)
</script>
<template><div class="shell page personal-layout"><aside class="personal-nav"><h3>个人中心</h3><RouterLink to="/profile">个人资料</RouterLink><RouterLink to="/orders" class="selected">我的订单</RouterLink><RouterLink to="/addresses">收货地址</RouterLink><RouterLink to="/account">账户安全</RouterLink></aside><section class="orders-content"><h1>我的订单</h1><el-tabs v-model="active"><el-tab-pane v-for="(label, value) in labels" :key="value" :label="label" :name="value" /></el-tabs><el-skeleton :loading="loading" animated :rows="8"><template #default><article v-for="order in displayed" :key="order.orderNo" class="order-card"><div class="order-meta"><span>{{ order.createdAt?.replace('T', ' ').slice(0, 19) || '订单创建成功' }}</span><b>订单号：{{ order.orderNo }}</b><em>{{ labels[order.status] || order.status }}</em><div class="order-actions"><el-button v-if="order.status === 'PENDING_PAYMENT'" size="small" type="primary" @click="$router.push({ path: '/payment', query: { orderNo: order.orderNo, amount: order.totalAmount } })">立即支付</el-button><el-button v-if="order.status === 'PENDING_PAYMENT'" size="small" type="danger" plain :loading="operating === order.orderNo" @click="cancel(order.orderNo)">取消订单</el-button><el-button v-if="order.status === 'SHIPPED'" size="small" type="primary" plain :loading="operating === order.orderNo" @click="confirm(order.orderNo)">确认收货</el-button></div></div><el-alert v-if="order.carrier || order.trackingNo" type="info" :closable="false" show-icon :title="`模拟物流：${order.carrier || '演示承运商'}　运单号 ${order.trackingNo || '-'}${order.shippedAt ? `　${order.shippedAt.replace('T', ' ').slice(0, 19)} 已发货` : ''}`" /><div v-for="item in order.items" :key="item.skuId" class="order-product"><img :src="item.mainImageUrl || 'https://placehold.co/200x200/eaf3ff/1677ff?text=DingDong'" :alt="item.productTitle" /><div><b>{{ item.productTitle }}</b><p>{{ item.specJson }}</p></div><span>¥{{ price(item.unitPrice) }} × {{ item.quantity }}</span><strong>¥{{ price(item.totalAmount) }}</strong></div></article><el-empty v-if="!displayed.length" description="暂无订单" /></template></el-skeleton></section></div></template>
